    procedureSteps: [{"title":"Krok 1","body":"Do držáku na laboratorním stojanu upevníme šikmo kovový žlábek (horní konec ve výši 30 až 40 cm na podložkou, spodní konec dosahuje ke knotu postavené svíčky)."},{"title":"Krok 2","body":"Do zkumavky se zátkou a trubičkou vypustíme z kartuše 2 až 3 cm vysoký sloupec kapalného propan-butanu (ventilek kartuše opřeme o vnější konec trubičky)."},{"title":"Krok 3","body":"Sledujeme, že v tlakové nádobě je propan-butan v kapalném stavu a kapalina ve zkumavce vře."},{"title":"Krok 4","body":"U dna na vnější straně zkumavky se tvoří jinovatka."},{"title":"Krok 5","body":"Do kapaliny ve zkumavce zasuneme teploměr a zjišťujeme, že teplota vroucí kapaliny je nižší než 0 °C."},{"title":"Krok 6","body":"Kapalinu ze zkumavky nalijeme do velké kádinky."},{"title":"Krok 7","body":"Látka se rychle odpaří a nádoba je na pohled prázdná."},{"title":"Krok 8","body":"Zapálíme svíčku pod připraveným žlábkem."},{"title":"Krok 9","body":"Z kádinky “jako by byla naplněna vodou” pozvolna nalijeme její obsah na horní část žlábku."},{"title":"Krok 10","body":"Pozorujeme, že směrem od svíčky nahoru žlábkem až do kádinky se šíří svítivý plamen."}],
