    procedureSteps: [{"title":"Krok 1","body":"Do držáku na laboratorním stojanu upevníme svisle odsávací zkumavku a vložíme do ní 2 – 3 cm vysokou vrstvu granulek zinku."},{"title":"Krok 2","body":"Přidáme asi ½ lžičky krystalického síranu měďnatého."},{"title":"Krok 3","body":"Zkumavku uzavřeme zátkou s otvorem, ve kterém je zasunuta stopka dělicí nálevky."},{"title":"Krok 4","body":"Na boční vývod zkumavky hadičkou připojíme odvodnou trubičku k jímání plynů nad vodou a její vývod ponoříme pod hladinu vody ve vaně."},{"title":"Krok 5","body":"Dělicí nálevku naplníme roztokem kyseliny chlorovodíkové."},{"title":"Krok 6","body":"V bezpečné vzdálenosti (min."},{"title":"Krok 7","body":"0,5 metru) zapálíme kahan."},{"title":"Krok 8","body":"Kyselinu chlorovodíkovou z dělicí nálevky pozvolna přikapáváme na zinek."},{"title":"Krok 9","body":"Vyvíjí se plyn, který uniká odvodnou trubičkou do vody."},{"title":"Krok 10","body":"Ponořením do vany naplníme zkumavku vodou, ještě pod vodou její ústí přiložíme ke konci trubičky a dno zkumavky naplněné vodou obrátíme dnem nahoru (zkumavku držíme u jejího ústí čtyřmi prsty a palec máme odkloněn)."},{"title":"Krok 11","body":"Unikající plyn je jímán do zkumavky a vytlačuje z ní vodu."},{"title":"Krok 12","body":"Jakmile je zkumavka naplněna, ještě pod vodou uzavřeme její ústí palcem, přiblížíme ji v šikmé poloze ústím nahoru k plameni kahanu, palec oddálíme a hrdlo zasuneme do plamene."}],
