    procedureSteps: [{"title":"Krok 1","body":"V Hofmannově přístroji provádíme elektrolýzu vody tak dlouho, až se trubice nad zápornou elektrodou plynem téměř naplní."},{"title":"Krok 2","body":"Po ukončení elektrolýzy na vývod nad zápornou elektrodou hadičkou připojíme rovnou trubičku a na vývod trubice s kladnou elektrodou 2x do pravého úhlu ohnutou trubičku."},{"title":"Krok 3","body":"Pod vývod ohnuté trubičky nasadíme zkumavku a vypustíme do ní plyn najímaný nad kladnou elektrodou, oddálíme ji a vložíme do ní žhnoucí třísku."},{"title":"Krok 4","body":"Na vývod u druhé, rovné, trubičky nasadíme dnem nahoru zkumavku a vypustíme do ní plyn, který vznikl na záporné elektrodě."},{"title":"Krok 5","body":"Zkumavku uzavřeme palcem ruky, přiblížíme ji mírně šikmo dnem dolu k plamenu kahanu, palec oddálíme a ústí zasuneme do plamene."}],
